import pandas as pd
import random

SRC = "steam_reviews.csv"
OUT = "reviews.csv"
TARGETS = {"english": 3000, "koreana": 1250, "_other": 750}

buckets = {k: [] for k in TARGETS}

def count(k):
    return sum(len(x) for x in buckets[k])

def done():
    return all(count(k) >= TARGETS[k] for k in TARGETS)

print("청크 읽는 중...")
for i, chunk in enumerate(pd.read_csv(SRC, chunksize=200_000, low_memory=False)):
    for lang in ("english", "koreana"):
        if count(lang) < TARGETS[lang]:
            rows = chunk[chunk.language == lang]
            need = TARGETS[lang] - count(lang)
            buckets[lang].append(rows.head(need))

    if count("_other") < TARGETS["_other"]:
        non_target = chunk[~chunk.language.isin(["english", "koreana"])]
        need = TARGETS["_other"] - count("_other")
        buckets["_other"].append(non_target.head(need))

    print(f"  chunk {i}: en={count('english')}, ko={count('koreana')}, other={count('_other')}")
    if done():
        break

parts = [pd.concat(buckets[k]).head(TARGETS[k]) for k in TARGETS]
df = pd.concat(parts).sample(frac=1, random_state=42).reset_index(drop=True)

df = df.rename(columns={
    "review": "text",
    "language": "lang",
    "author.playtime_forever": "playtime_minutes",
    "timestamp_created": "posted_at_unix",
})
df["playtime_hours"] = (df["playtime_minutes"].fillna(0) / 60).round(1)
df["posted_at"] = pd.to_datetime(df["posted_at_unix"], unit="s", errors="coerce")
df = df[["review_id", "text", "lang", "recommended", "playtime_hours", "posted_at"]]

spam_texts = [
    "BUY CHEAP CS:GO SKINS www.totallylegit-skins.example",
    "Free V-bucks generator click here!!! bit.ly/fake",
    "아이템 현금거래 카톡 fake123 최저가",
    "Visit my profile for free keys!!!",
    "10/10 would recommend - sponsored by NordVPN",
]
rng = random.Random(42)
spam_idx = rng.sample(range(len(df)), k=int(len(df) * 0.05))
spam_set = set(spam_idx)
for i, idx in enumerate(spam_idx):
    df.loc[idx, "text"] = spam_texts[i % len(spam_texts)]

remaining = [i for i in range(len(df)) if i not in spam_set]
broken_idx = random.Random(43).sample(remaining, k=int(len(df) * 0.03))
for idx in broken_idx:
    try:
        t = str(df.loc[idx, "text"])
        df.loc[idx, "text"] = t.encode("utf-8").decode("latin-1")
    except Exception:
        pass

df.to_csv(OUT, index=False, encoding="utf-8")
print(f"\n생성 완료: {OUT} ({len(df)} 행)")
print("언어 분포:")
print(df.lang.value_counts())

